#include <stdio.h>

int fn(int *a, int *b) {
    *a = *a + *b;
    return (*b = *a - *b);
}

int main() {
    int x = 2;
    int y = 3;

    printf("%d", fn(&x, &y) + y);
    return 0;
}

public class Main {
    static int x = f();

    static int f() {
        System.out.print("A");
        return 1;
    }

    static {
        x++;
    }

    public static void main(String[] args) {
        System.out.print(x);
    }
}

#include <stdio.h>

typedef struct {
    int x;
} Struct;

void change(Struct *a, Struct b) {
    a->x += b.x;
    b.x = 100;
    a = &b;
    a->x = 200;
}

int main() {
    Struct b1 = {3};
    Struct b2 = {4};
    change(&b1, b2);
    printf("%d ", b1.x);
    return 0;
}

public class Main {
    static void func(int[] a) {
        a[0]++;
        a = new int[]{5};
    }

    public static void main(String[] args) {
        int[] arr = {2};
        func(arr);
        System.out.println(arr[0]);
    }
}

public class Main {
    int result = 0;

    int test() {
        try {
            return 1;
        } finally {
            result = 2;
        }
    }

    public static void main(String[] args) {
        Main p = new Main();
        System.out.print(p.test());
    }
}

#include <stdio.h>

void func(int *p) {
    int temp[] = {0, 1, 2};
    p = temp;
    p[0] = 9;
}

int main() {
    int arr[] = {3, 4, 5};
    func(arr);
    printf("%d", arr[0]);
    return 0;
}
